/**
 * D3 + D4 — Talent Signal Master + Concern Intelligence Bridge
 * 300 reusable atomic signals powering EI, Career Builder,
 * Leadership/Future/Promotion/Role Readiness from one source.
 * Additive + flag-gated: FF_CAREER_GRAPH=1. Flag-off → 503. Never throws.
 */
import type { Express, Request, Response } from 'express';
import type { Pool } from 'pg';

const FLAG = 'FF_CAREER_GRAPH';
const flagOn = () => process.env[FLAG] === '1';
type AuthFn = (req: Request, res: Response, next: () => void) => void;

const cache = new Map<string, { data: unknown; ts: number }>();
const CACHE_TTL = 60_000;
const getCached = <T>(k: string): T | null => { const e = cache.get(k); return e && Date.now() - e.ts < CACHE_TTL ? e.data as T : null; };
const setCache = (k: string, d: unknown) => cache.set(k, { data: d, ts: Date.now() });
const bustCache = () => cache.clear();

let schemaReady = false;
async function ensureSchema(pool: Pool): Promise<void> {
  if (schemaReady) return;
  await pool.query(`
    CREATE TABLE IF NOT EXISTS ti_signal_master (
      id SERIAL PRIMARY KEY,
      signal_code TEXT NOT NULL UNIQUE,
      signal_name TEXT NOT NULL,
      description TEXT,
      category TEXT NOT NULL,
      subcategory TEXT,
      behavioral_indicator TEXT,
      cognitive_indicator TEXT,
      future_relevance INTEGER DEFAULT 5 CHECK (future_relevance BETWEEN 1 AND 10),
      is_active BOOLEAN DEFAULT true,
      created_at TIMESTAMPTZ DEFAULT NOW(),
      updated_at TIMESTAMPTZ DEFAULT NOW()
    );
    CREATE INDEX IF NOT EXISTS idx_ti_signal_category ON ti_signal_master(category);
    CREATE TABLE IF NOT EXISTS ti_signal_competency_map (
      id SERIAL PRIMARY KEY,
      signal_id INTEGER NOT NULL REFERENCES ti_signal_master(id) ON DELETE CASCADE,
      blueprint_key TEXT NOT NULL,
      competency_name TEXT NOT NULL,
      weight NUMERIC(5,4) DEFAULT 0.5 CHECK (weight BETWEEN 0 AND 1),
      direction TEXT CHECK (direction IN ('positive','negative','neutral')) DEFAULT 'positive',
      created_at TIMESTAMPTZ DEFAULT NOW(),
      UNIQUE(signal_id, blueprint_key, competency_name)
    );
    CREATE INDEX IF NOT EXISTS idx_ti_scm_signal ON ti_signal_competency_map(signal_id);
    CREATE INDEX IF NOT EXISTS idx_ti_scm_blueprint ON ti_signal_competency_map(blueprint_key);
    CREATE TABLE IF NOT EXISTS ti_signal_concern_map (
      id SERIAL PRIMARY KEY,
      signal_id INTEGER NOT NULL REFERENCES ti_signal_master(id) ON DELETE CASCADE,
      concern_code TEXT NOT NULL,
      concern_label TEXT,
      relevance_score NUMERIC(5,4) DEFAULT 0.7 CHECK (relevance_score BETWEEN 0 AND 1),
      created_at TIMESTAMPTZ DEFAULT NOW(),
      UNIQUE(signal_id, concern_code)
    );
    CREATE INDEX IF NOT EXISTS idx_ti_sconcern_signal ON ti_signal_concern_map(signal_id);
    CREATE TABLE IF NOT EXISTS ti_concern_competency_hierarchy (
      id SERIAL PRIMARY KEY,
      competency_name TEXT NOT NULL,
      blueprint_key TEXT NOT NULL,
      concern_domain TEXT NOT NULL,
      concern_label TEXT,
      signal_strength TEXT CHECK (signal_strength IN ('strong','moderate','weak')) DEFAULT 'moderate',
      created_at TIMESTAMPTZ DEFAULT NOW(),
      UNIQUE(competency_name, blueprint_key, concern_domain)
    );
  `);
  schemaReady = true;
}

