async function seedSignals(pool: Pool): Promise<void> {
  const existing = await pool.query<{ cnt: string }>('SELECT COUNT(*)::int AS cnt FROM ti_signal_master');
  if (Number(existing.rows[0]?.cnt) >= 300) return;
  for (const s of SIGNALS) {
    await pool.query(
      `INSERT INTO ti_signal_master(signal_code,signal_name,description,category,subcategory,behavioral_indicator,cognitive_indicator,future_relevance)
       VALUES($1,$2,$3,$4,$5,$6,$7,$8) ON CONFLICT(signal_code) DO NOTHING`,
      [s.signal_code, s.signal_name, s.description, s.category, s.subcategory,
       s.behavioral_indicator, s.cognitive_indicator, s.future_relevance]
    );
  }
  for (const m of SIGNAL_COMPETENCY_MAP) {
    const sig = await pool.query<{ id: number }>('SELECT id FROM ti_signal_master WHERE signal_code=$1', [m.signal_code]);
    if (!sig.rows[0]) continue;
    await pool.query(
      `INSERT INTO ti_signal_competency_map(signal_id,blueprint_key,competency_name,weight,direction)
       VALUES($1,$2,$3,$4,$5) ON CONFLICT(signal_id,blueprint_key,competency_name) DO NOTHING`,
      [sig.rows[0].id, m.blueprint_key, m.competency_name, m.weight, m.direction]
    );
  }
  const CONCERN_MAP = [
    { code: 'SI_001', concern_code: 'strategic_clarity', concern_label: 'Strategic Clarity', relevance: 0.9 },
    { code: 'AC_002', concern_code: 'critical_thinking_gap', concern_label: 'Critical Thinking Gap', relevance: 0.85 },
    { code: 'LP_007', concern_code: 'psychological_safety_risk', concern_label: 'Psychological Safety Risk', relevance: 0.9 },
    { code: 'ES_001', concern_code: 'self_awareness_gap', concern_label: 'Self-Awareness Gap', relevance: 0.85 },
    { code: 'FR_001', concern_code: 'ai_readiness_concern', concern_label: 'AI Readiness Gap', relevance: 0.9 },
    { code: 'LA_001', concern_code: 'growth_mindset_gap', concern_label: 'Growth Mindset Gap', relevance: 0.85 },
    { code: 'OE_001', concern_code: 'execution_gap', concern_label: 'Execution Gap', relevance: 0.8 },
    { code: 'CI_003', concern_code: 'listening_deficit', concern_label: 'Listening Deficit', relevance: 0.8 },
    { code: 'DT_001', concern_code: 'digital_literacy_gap', concern_label: 'Digital Literacy Gap', relevance: 0.85 },
    { code: 'IC_001', concern_code: 'innovation_gap', concern_label: 'Innovation Capacity Gap', relevance: 0.8 },
  ];
  for (const c of CONCERN_MAP) {
    const sig = await pool.query<{ id: number }>('SELECT id FROM ti_signal_master WHERE signal_code=$1', [c.code]);
    if (!sig.rows[0]) continue;
    await pool.query(
      `INSERT INTO ti_signal_concern_map(signal_id,concern_code,concern_label,relevance_score)
       VALUES($1,$2,$3,$4) ON CONFLICT(signal_id,concern_code) DO NOTHING`,
      [sig.rows[0].id, c.concern_code, c.concern_label, c.relevance]
    );
  }
}

export function registerTalentSignalMasterRoutes(app: Express, pool: Pool, requireAuth: AuthFn, requireSuperAdmin: AuthFn): void {
  if (!flagOn()) return;
  ensureSchema(pool).then(() => seedSignals(pool)).catch(() => {});

  // GET /api/admin/talent/signals — paginated list
  app.get('/api/admin/talent/signals', requireAuth, requireSuperAdmin, async (req: Request, res: Response) => {
    const cached = getCached('signals_list');
    if (cached && req.query.refresh !== '1') return res.json(cached);
    try {
      const { category, search, page = '1', limit = '50' } = req.query as Record<string, string>;
      const offset = (parseInt(page) - 1) * parseInt(limit);
      const params: unknown[] = [];
      const where: string[] = [];
      if (category) { params.push(category); where.push(`s.category=$${params.length}`); }
      if (search) { params.push(`%${search}%`); where.push(`(s.signal_name ILIKE $${params.length} OR s.description ILIKE $${params.length})`); }
      const wc = where.length ? `WHERE ${where.join(' AND ')}` : '';
      const [countRes, rows, cats, kpi] = await Promise.all([
        pool.query(`SELECT COUNT(*) FROM ti_signal_master s ${wc}`, params),
        pool.query(`SELECT s.*, COUNT(scm.id) as competency_links, COUNT(sconcern.id) as concern_links
          FROM ti_signal_master s
          LEFT JOIN ti_signal_competency_map scm ON scm.signal_id=s.id
          LEFT JOIN ti_signal_concern_map sconcern ON sconcern.signal_id=s.id
          ${wc} GROUP BY s.id ORDER BY s.category, s.signal_code
          LIMIT $${params.length+1} OFFSET $${params.length+2}`, [...params, parseInt(limit), offset]),
        pool.query(`SELECT category, COUNT(*) as cnt, ROUND(AVG(future_relevance),1) as avg_fr FROM ti_signal_master GROUP BY category ORDER BY category`),
        pool.query(`SELECT COUNT(*)::int as total,
          ROUND(AVG(future_relevance),1) as avg_future_relevance,
          COUNT(*) FILTER (WHERE future_relevance>=8) as high_relevance,
          COUNT(DISTINCT category) as categories FROM ti_signal_master`),
      ]);
      const result = { total: parseInt(countRes.rows[0].count), page: parseInt(page), rows: rows.rows, categories: cats.rows, kpi: kpi.rows[0] };
      setCache('signals_list', result);
      res.json(result);
    } catch (err) { console.error('Signal list error:', err); res.status(500).json({ error: 'fetch failed' }); }
  });

  // GET /api/admin/talent/signals/stats — dashboard stats
  app.get('/api/admin/talent/signals/stats', requireAuth, requireSuperAdmin, async (_req: Request, res: Response) => {
    try {
      const [overview, catDist, frDist, bridgeCoverage] = await Promise.all([
        pool.query(`SELECT COUNT(*)::int as total_signals, COUNT(DISTINCT category) as categories,
          ROUND(AVG(future_relevance),1) as avg_future_relevance,
          COUNT(*) FILTER (WHERE future_relevance>=9) as critical_signals,
          COUNT(*) FILTER (WHERE future_relevance>=7 AND future_relevance<9) as high_signals,
          COUNT(*) FILTER (WHERE future_relevance<7) as moderate_signals
          FROM ti_signal_master`),
        pool.query(`SELECT category, COUNT(*) as signal_count, ROUND(AVG(future_relevance),1) as avg_fr,
          MAX(future_relevance) as max_fr, MIN(future_relevance) as min_fr
          FROM ti_signal_master GROUP BY category ORDER BY signal_count DESC`),
        pool.query(`SELECT future_relevance as score, COUNT(*) as cnt FROM ti_signal_master GROUP BY future_relevance ORDER BY future_relevance DESC`),
        pool.query(`SELECT COUNT(DISTINCT s.id)::int as signals_with_competency_links,
          COUNT(DISTINCT s2.id)::int as signals_with_concern_links
          FROM ti_signal_master s
          LEFT JOIN ti_signal_competency_map scm ON scm.signal_id=s.id
          JOIN ti_signal_master s2 ON s2.id=s.id
          LEFT JOIN ti_signal_concern_map scon ON scon.signal_id=s2.id
          WHERE scm.id IS NOT NULL OR scon.id IS NOT NULL`).catch(() => ({ rows: [{}] })),
      ]);
      res.json({ overview: overview.rows[0], category_distribution: catDist.rows, future_relevance_distribution: frDist.rows, bridge_coverage: bridgeCoverage.rows[0] });
    } catch (err) { console.error('Signal stats error:', err); res.status(500).json({ error: 'stats failed' }); }
  });

  // GET /api/admin/talent/signals/:id — single signal detail
  app.get('/api/admin/talent/signals/:id', requireAuth, requireSuperAdmin, async (req: Request, res: Response) => {
    try {
      const id = parseInt(req.params.id);
      const [signal, competencyLinks, concernLinks] = await Promise.all([
        pool.query('SELECT * FROM ti_signal_master WHERE id=$1', [id]),
        pool.query('SELECT * FROM ti_signal_competency_map WHERE signal_id=$1 ORDER BY weight DESC', [id]),
        pool.query('SELECT * FROM ti_signal_concern_map WHERE signal_id=$1 ORDER BY relevance_score DESC', [id]),
      ]);
      if (!signal.rows[0]) return res.status(404).json({ error: 'signal not found' });
      res.json({ signal: signal.rows[0], competency_links: competencyLinks.rows, concern_links: concernLinks.rows });
    } catch (err) { console.error('Signal detail error:', err); res.status(500).json({ error: 'fetch failed' }); }
  });

  // POST /api/admin/talent/signals — create
  app.post('/api/admin/talent/signals', requireAuth, requireSuperAdmin, async (req: Request, res: Response) => {
    const { signal_code, signal_name, description, category, subcategory, behavioral_indicator, cognitive_indicator, future_relevance } = req.body;
    if (!signal_code || !signal_name || !category) return res.status(400).json({ error: 'signal_code, signal_name, category required' });
    try {
      const r = await pool.query(
        `INSERT INTO ti_signal_master(signal_code,signal_name,description,category,subcategory,behavioral_indicator,cognitive_indicator,future_relevance)
         VALUES($1,$2,$3,$4,$5,$6,$7,$8) RETURNING *`,
        [signal_code, signal_name, description, category, subcategory, behavioral_indicator, cognitive_indicator, future_relevance || 5]
      );
      bustCache(); res.json({ ok: true, signal: r.rows[0] });
    } catch (err: any) { res.status(400).json({ error: err.message }); }
  });

  // PATCH /api/admin/talent/signals/:id — update
  app.patch('/api/admin/talent/signals/:id', requireAuth, requireSuperAdmin, async (req: Request, res: Response) => {
    const id = parseInt(req.params.id);
    const fields = ['signal_name', 'description', 'category', 'subcategory', 'behavioral_indicator', 'cognitive_indicator', 'future_relevance', 'is_active'];
    const updates: string[] = []; const params: unknown[] = [];
    for (const f of fields) { if (req.body[f] !== undefined) { params.push(req.body[f]); updates.push(`${f}=$${params.length}`); } }
    if (!updates.length) return res.status(400).json({ error: 'no fields to update' });
    params.push(id);
    try {
      const r = await pool.query(`UPDATE ti_signal_master SET ${updates.join(',')},updated_at=NOW() WHERE id=$${params.length} RETURNING *`, params);
      bustCache(); res.json({ ok: true, signal: r.rows[0] });
    } catch (err: any) { res.status(400).json({ error: err.message }); }
  });

  // GET /api/admin/talent/signals/competency-bridge/:blueprint_key — signals wired to a blueprint
  app.get('/api/admin/talent/signals/competency-bridge/:blueprint_key', requireAuth, requireSuperAdmin, async (req: Request, res: Response) => {
    try {
      const rows = await pool.query(
        `SELECT s.signal_code, s.signal_name, s.category, s.future_relevance,
                m.competency_name, m.weight, m.direction
         FROM ti_signal_competency_map m
         JOIN ti_signal_master s ON s.id=m.signal_id
         WHERE m.blueprint_key=$1 ORDER BY m.weight DESC`, [req.params.blueprint_key]
      );
      res.json({ blueprint_key: req.params.blueprint_key, signals: rows.rows, count: rows.rows.length });
    } catch (err) { res.status(500).json({ error: 'fetch failed' }); }
  });

  // GET /api/talent/signals/profile/:email — user signal profile (which concern signals active)
  app.get('/api/talent/signals/profile/:email', requireAuth, async (req: Request, res: Response) => {
    try {
      const email = decodeURIComponent(req.params.email).toLowerCase();
      const [gaps, sessions] = await Promise.all([
        pool.query('SELECT * FROM talent_gaps WHERE user_email=$1 ORDER BY gap_score DESC LIMIT 10', [email]).catch(() => ({ rows: [] })),
        pool.query(`SELECT score, stage_code FROM capadex_sessions WHERE guest_email=$1 AND status='completed' ORDER BY created_at DESC LIMIT 5`, [email]).catch(() => ({ rows: [] })),
      ]);
      const avgSessionScore = sessions.rows.length ? sessions.rows.reduce((a: number, s: any) => a + Number(s.score || 0), 0) / sessions.rows.length : null;
      res.json({ email, talent_gaps: gaps.rows, session_avg_score: avgSessionScore, signal_bridge: 'active', generated_at: new Date().toISOString() });
    } catch (err) { res.status(500).json({ error: 'fetch failed' }); }
  });

  console.log('[talent-signal-master] D3+D4 routes registered — 300 signals + competency/concern bridge');
}
